package main

import (
    "io/ioutil"
    "os"
)

// Compliant: Secure file permissions
func createConfigFile() error {
    // GOOD: 0600 allows read/write only for owner
    return ioutil.WriteFile("config.txt", []byte("secret"), 0600)
}

func createLogDirectory() error {
    // GOOD: 0750 allows read/write/execute for owner, read/execute for group only
    return os.Mkdir("/var/log/app", 0750)
}

func createPrivateKeyFile(keyData []byte) error {
    // GOOD: Private key file readable only by owner
    return ioutil.WriteFile("/etc/ssl/private/app.key", keyData, 0600)
}

func createSecureTempFile(data []byte) error {
    // GOOD: Create temp file with secure permissions
    file, err := ioutil.TempFile("/tmp", "app-temp")
    if err != nil {
        return err
    }
    defer file.Close()

    // GOOD: Explicitly set secure permissions
    if err := file.Chmod(0600); err != nil {
        return err
    }

    _, err = file.Write(data)
    return err
}

func saveCredentials(username, password string) error {
    // GOOD: Credentials file with owner-only permissions
    creds := username + ":" + password
    return ioutil.WriteFile("/home/user/.credentials", []byte(creds), 0600)
}

// GOOD: Helper function to create files with secure permissions
func writeSecureFile(filename string, data []byte) error {
    // Create file with owner-only read/write permissions
    file, err := os.OpenFile(filename, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0600)
    if err != nil {
        return err
    }
    defer file.Close()

    _, err = file.Write(data)
    return err
}

// GOOD: Create directory with appropriate permissions
func createSecureDirectory(path string) error {
    // 0700 - owner has full access, no access for group or others
    return os.MkdirAll(path, 0700)
}

// GOOD: Function to check and fix file permissions
func ensureSecurePermissions(filename string) error {
    info, err := os.Stat(filename)
    if err != nil {
        return err
    }

    // Check if permissions are too permissive
    mode := info.Mode()
    if mode.Perm() & 0077 != 0 {
        // Fix permissions to be owner-only
        return os.Chmod(filename, 0600)
    }

    return nil
}
